import{l as a,a as r,c as o,a6 as t}from"./chunks/framework.BlM2IGSi.js";const g=JSON.parse('{"title":"codegraph","description":"","frontmatter":{},"headers":[],"relativePath":"ai/cli/codegraph.md","filePath":"ai/cli/codegraph.md"}'),l={name:"ai/cli/codegraph.md"};function h(i,e,p,c,d,n){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="codegraph" tabindex="-1">codegraph <a class="header-anchor" href="#codegraph" aria-label="Permalink to &quot;codegraph&quot;">​</a></h1><h2 id="why" tabindex="-1">why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;why&quot;">​</a></h2><p>Agent 在分析需求问题的时候，搜索、读取、分析代码耗时非常久。</p><p>现有两种解决方案：</p><ol><li>文件内容分块，再处理</li><li>借助本地代码索引</li></ol><p>codegraph 就是提供了本地代码索引的方式来加速代码分析。</p><p>本文介绍的 codegraph 是 <a href="https://github.com/colbymchenry/codegraph" target="_blank" rel="noreferrer">colbymchenry/codegraph</a>，采用 ts + tree-sitter + sqlite 实现索引，提供了 CLI、MCP、npm 包集成 3 种使用方式。</p><p>另一提供索引的工具 <a href="https://github.com/CodeGraphContext/CodeGraphContext" target="_blank" rel="noreferrer">CodeGraphContext/CodeGraphContext</a>，使用了 python + tree-sitter + kuzu db，暂未尝试。</p><p>还有一更默认带索引能力的 Agent：Aider，内部使用了同样的代码库索引，使得在大型多文件项目中，Agent 能很好地理解项目。</p><h2 id="how" tabindex="-1">how <a class="header-anchor" href="#how" aria-label="Permalink to &quot;how&quot;">​</a></h2><p>根据 codegraph 仓库中的文档，先生成一个技能。再通过技能去使用 codegraph</p><p>技能补充要求：</p><ol><li>使用 CLI 模式</li><li>codegraph 无法使用时，先安装和建立索引</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>从 0.9.9 版本开始，不再建议用 skill，使用官方推荐的 MCP 模式即可。会根据 MCP 工具描述优先用 explore 检索。</p></div><h2 id="what" tabindex="-1">what <a class="header-anchor" href="#what" aria-label="Permalink to &quot;what&quot;">​</a></h2><p>场景使用示例：</p><ul><li>/codegraph 安装 codegraph</li><li>/codegraph 建立项目索引</li><li>/codegraph 分析 xxx 的调用链</li><li>/codegraph 分析改动的影响范围</li><li>/codegraph 追踪从项目运行入口到某个问题的执行路径</li><li>/codegraph 分析项目中 xxx 功能的交互方式</li><li>/codegraph 检查项目中是否有未使用到的方法</li><li>/codegraph 计算 xxx 函数的圈复杂度</li><li>/codegraph 查找代码库中最复杂的 3 个函数</li></ul>',17)])])}const _=a(l,[["render",h]]);export{g as __pageData,_ as default};
